/**
 * Products API client — hand-written (not generated by orval).
 * Provides functions to interact with /api/products and /api/products/sales.
 */
import { customFetch } from "../custom-fetch";

export interface Product {
  id: string;
  agentId: string;
  name: string;
  barcode?: string | null;
  price: number;
  stock?: number | null;
  category?: string | null;
  description?: string | null;
  createdAt: string;
  updatedAt: string;
}

export interface ProductSale {
  id: string;
  agentId: string;
  productId?: string | null;
  productName: string;
  unitPrice: number;
  quantity: number;
  totalPrice: number;
  barcode?: string | null;
  note?: string | null;
  createdAt: string;
}

// ─── Products ────────────────────────────────────────────────────────────────

export async function getProducts(): Promise<Product[]> {
  return customFetch<Product[]>("/api/products", { method: "GET" });
}

export async function getProductByBarcode(barcode: string): Promise<Product> {
  return customFetch<Product>(`/api/products/barcode/${encodeURIComponent(barcode)}`, { method: "GET" });
}

export async function createProduct(data: {
  name: string;
  barcode?: string;
  price: number;
  stock?: number;
  category?: string;
  description?: string;
}): Promise<Product> {
  return customFetch<Product>("/api/products", {
    method: "POST",
    body: JSON.stringify(data),
  });
}

export async function updateProduct(id: string, data: {
  name?: string;
  barcode?: string | null;
  price?: number;
  stock?: number | null;
  category?: string | null;
  description?: string | null;
}): Promise<Product> {
  return customFetch<Product>(`/api/products/${id}`, {
    method: "PUT",
    body: JSON.stringify(data),
  });
}

export async function deleteProduct(id: string): Promise<{ success: boolean }> {
  return customFetch<{ success: boolean }>(`/api/products/${id}`, { method: "DELETE" });
}

// ─── Product Sales ────────────────────────────────────────────────────────────

export async function getProductSales(): Promise<ProductSale[]> {
  return customFetch<ProductSale[]>("/api/products/sales", { method: "GET" });
}

export async function createProductSale(data: {
  id?: string;
  productId?: string | null;
  productName: string;
  unitPrice: number;
  quantity: number;
  totalPrice: number;
  barcode?: string | null;
  note?: string | null;
  createdAt?: string;
}): Promise<ProductSale> {
  return customFetch<ProductSale>("/api/products/sales", {
    method: "POST",
    body: JSON.stringify(data),
  });
}
